/* Lottie Web Library - Minimal stub for graceful degradation */
if (typeof lottie === 'undefined') {
    window.lottie = {
        loadAnimation: function(params) {
            console.warn('Lottie not loaded, using CSS animations instead');
            return {
                play: function() {},
                stop: function() {},
                destroy: function() {}
            };
        }
    };
}